import{_ as e,o as a,c as s,a2 as o}from"./chunks/framework.CBOyQ9KN.js";const u=JSON.parse('{"title":"Glass UI 品牌资源分析","description":"","frontmatter":{},"headers":[],"relativePath":"10-glass-ui/glass-ui-analysis.md","filePath":"10-glass-ui/glass-ui-analysis.md","lastUpdated":null}'),l={name:"10-glass-ui/glass-ui-analysis.md"};function r(d,t,n,i,c,h){return a(),s("div",null,[...t[0]||(t[0]=[o('<h1 id="glass-ui-品牌资源分析" tabindex="-1">Glass UI 品牌资源分析 <a class="header-anchor" href="#glass-ui-品牌资源分析" aria-label="Permalink to &quot;Glass UI 品牌资源分析&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>Glass 是 Cursor 的 Web/Cloud UI 层，提供<strong>启动画面、品牌动画、云环境设置界面</strong>。</p><h2 id="资源文件" tabindex="-1">资源文件 <a class="header-anchor" href="#资源文件" aria-label="Permalink to &quot;资源文件&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文件</th><th style="text-align:center;">大小</th><th style="text-align:center;">格式</th><th>用途</th></tr></thead><tbody><tr><td><code>cursor-splash-logo-normal.png</code></td><td style="text-align:center;">19KB</td><td style="text-align:center;">PNG</td><td>正常启动画面 Logo（桌面端）</td></tr><tr><td><code>cursor-splash-logo-glass.png</code></td><td style="text-align:center;">48KB</td><td style="text-align:center;">PNG</td><td>Glass 主题启动画面 Logo（Web/Cloud 端）</td></tr><tr><td><code>cursor-logo-for-dark-theme.webm</code></td><td style="text-align:center;">128KB</td><td style="text-align:center;">WebM</td><td>深色主题动态动画 Logo</td></tr><tr><td><code>cursor-logo-for-light-theme.webm</code></td><td style="text-align:center;">131KB</td><td style="text-align:center;">WebM</td><td>浅色主题动态动画 Logo</td></tr><tr><td><code>cloud-environment-setup.png</code></td><td style="text-align:center;">59KB</td><td style="text-align:center;">PNG</td><td>云环境设置界面插图</td></tr></tbody></table><h2 id="目录位置" tabindex="-1">目录位置 <a class="header-anchor" href="#目录位置" aria-label="Permalink to &quot;目录位置&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>out/vs/glass/browser/media/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="功能分析" tabindex="-1">功能分析 <a class="header-anchor" href="#功能分析" aria-label="Permalink to &quot;功能分析&quot;">​</a></h2><h3 id="启动画面" tabindex="-1">启动画面 <a class="header-anchor" href="#启动画面" aria-label="Permalink to &quot;启动画面&quot;">​</a></h3><p>Cursor 根据环境选择启动画面：</p><ul><li><strong>桌面端</strong>: <code>cursor-splash-logo-normal.png</code></li><li><strong>Glass (云端)</strong>: <code>cursor-splash-logo-glass.png</code></li></ul><h3 id="动画-logo" tabindex="-1">动画 Logo <a class="header-anchor" href="#动画-logo" aria-label="Permalink to &quot;动画 Logo&quot;">​</a></h3><p><code>.webm</code> 格式的动画 Logo 在启动时播放，根据系统主题选择：</p><ul><li>深色系统主题 → <code>cursor-logo-for-dark-theme.webm</code></li><li>浅色系统主题 → <code>cursor-logo-for-light-theme.webm</code></li></ul><h3 id="云环境设置" tabindex="-1">云环境设置 <a class="header-anchor" href="#云环境设置" aria-label="Permalink to &quot;云环境设置&quot;">​</a></h3><p><code>cloud-environment-setup.png</code> 用于 Cloud Agent 环境配置界面的插图。</p><h2 id="glass-模式触发" tabindex="-1">Glass 模式触发 <a class="header-anchor" href="#glass-模式触发" aria-label="Permalink to &quot;Glass 模式触发&quot;">​</a></h2><p>当 Cursor 以 <code>--glass</code> 参数启动或在 Web 环境中运行时启用 Glass UI 层。</p>',18)])])}const p=e(l,[["render",r]]);export{u as __pageData,p as default};
